{"code": "import json

# Load books data
books_var = locals()['var_functions.query_db:8']
with open(books_var, 'r') as f:
    books = json.load(f)

# Filter for Literature & Fiction in English
lit_fiction_books = []
for book in books:
    categories = str(book.get('categories', ''))
    details = str(book.get('details', ''))

    if 'Literature & Fiction' in categories and 'English' in details:
        lit_fiction_books.append(book)

# Load reviews data
reviews_var = locals()['var_functions.query_db:26']
with open(reviews_var, 'r') as f:
    reviews = json.load(f)

# Create mapping from purchase_id to list of ratings
purchase_ratings = {}
for review in reviews:
    purchase_id = review.get('purchase_id')
    rating = float(review.get('rating', 0))

    if purchase_id not in purchase_ratings:
        purchase_ratings[purchase_id] = []
    purchase_ratings[purchase_id].append(rating)

# Calculate average rating for each purchase_id
purchase_avg_ratings = {}
for purchase_id, ratings in purchase_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    purchase_avg_ratings[purchase_id] = {
        'avg_rating': avg_rating,
        'rating_count': len(ratings),
        'ratings': ratings
    }

print('__RESULT__:')
print(json.dumps({
    'books': len(lit_fiction_books),
    'reviews': len(reviews),
    'unique_purchases_with_ratings': len(purchase_avg_ratings),
    'sample_purchase_rating': dict(list(purchase_avg_ratings.items())[:3])
}))"}

